#include <stdio.h>
int main() {
    int T, n;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &n) != 1) break;
        int first = 1;
        for (int i = 2; i <= n; i += 2) {
            if (!first) printf(" ");
            printf("%d", i);
            first = 0;
        }
        printf("\n");
    }
    return 0;
}

